using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public string DocumentText { get; set; } = string.Empty;

    /// <summary>Maximum number of sentences in the summary (default 3).</summary>
    [Range(1, 20)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public string Summary { get; set; } = string.Empty;
    public int OriginalLength { get; set; }
    public int SummaryLength { get; set; }
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

public interface IDocumentSummarizer
{
    string Summarize(string text, int maxSentences);
}

/// <summary>
/// Extractive summarizer that scores sentences by word-frequency and returns the
/// top-ranked ones in their original document order.
/// </summary>
public partial class DocumentSummarizer : IDocumentSummarizer
{
    public string Summarize(string text, int maxSentences)
    {
        var sentences = SplitSentences(text);
        if (sentences.Length <= maxSentences)
            return string.Join(" ", sentences);

        var wordFrequency = BuildWordFrequency(sentences);
        var scored = sentences
            .Select((s, i) => (Index: i, Score: ScoreSentence(s, wordFrequency)))
            .OrderByDescending(x => x.Score)
            .Take(maxSentences)
            .OrderBy(x => x.Index) // preserve original order
            .Select(x => sentences[x.Index]);

        return string.Join(" ", scored);
    }

    private static string[] SplitSentences(string text)
    {
        return SentenceRegex()
            .Split(text.Trim())
            .Select(s => s.Trim())
            .Where(s => s.Length > 0)
            .ToArray();
    }

    private static Dictionary<string, int> BuildWordFrequency(string[] sentences)
    {
        var freq = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
        foreach (var sentence in sentences)
        {
            foreach (var word in TokenizeWords(sentence))
            {
                if (word.Length < 3) continue; // skip very short words
                freq[word] = freq.GetValueOrDefault(word) + 1;
            }
        }
        return freq;
    }

    private static double ScoreSentence(string sentence, Dictionary<string, int> freq)
    {
        var words = TokenizeWords(sentence);
        if (words.Length == 0) return 0;
        return words.Sum(w => freq.GetValueOrDefault(w)) / (double)words.Length;
    }

    private static string[] TokenizeWords(string sentence) =>
        WordRegex().Matches(sentence).Select(m => m.Value.ToLowerInvariant()).ToArray();

    [GeneratedRegex(@"(?<=[.!?])\s+")]
    private static partial Regex SentenceRegex();

    [GeneratedRegex(@"\w+")]
    private static partial Regex WordRegex();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController(IDocumentSummarizer summarizer) : ControllerBase
{
    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var summary = summarizer.Summarize(request.DocumentText, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalLength = request.DocumentText.Length,
            SummaryLength = summary.Length
        });
    }
}

